    func fetchData(completionHandler: @escaping ([String : Any]?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseUrl)/users") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completionHandler(nil, error)
                return
            }
            
            do {
                let json = try JSONSerialization.jsonObject(with: data!, options: [])
                completionHandler(json as? [String : Any], nil)
            } catch {
                completionHandler(nil, error)
            }
        }.resume()
    }
    
    func authenticateUser(username: String, password: String, completionHandler: @escaping ([String : Any]?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.baseUrl)/users/login") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = "{\"username\":\"\(username)\",\"password\":\"\(password}\"".data(using: .utf8)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completionHandler(nil, error)
                return
            }
            
            do {
                let json = try JSONSerialization.jsonObject(with: data!, options: [])
                completionHandler(json as? [String : Any], nil)
            } catch {
                completionHandler(nil, error)
            }
        }.resume()
    }
